import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { FiX } from 'react-icons/fi';

const CookieConsent = () => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    // Check if user has already made a choice
    const consent = localStorage.getItem('toolbite_cookie_consent');
    if (!consent) {
      // Delay showing it slightly for a better user experience
      const timer = setTimeout(() => {
        setIsVisible(true);
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, []);

  const handleAccept = () => {
    localStorage.setItem('toolbite_cookie_consent', 'accepted');
    setIsVisible(false);
  };

  const handleDecline = () => {
    localStorage.setItem('toolbite_cookie_consent', 'declined');
    setIsVisible(false);
  };

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ y: 50, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 50, opacity: 0 }}
          transition={{ type: "spring", stiffness: 300, damping: 25 }}
          className="fixed bottom-4 left-4 right-4 md:left-auto md:right-6 md:w-[400px] bg-white rounded-2xl shadow-[0_10px_40px_rgba(0,0,0,0.1)] border border-slate-100 p-6 z-[100]"
        >
          <div className="flex justify-between items-start mb-3">
            <div className="flex items-center gap-2">
              <span className="text-xl">🍪</span>
              <h3 className="font-bold text-slate-800">We value your privacy</h3>
            </div>
            <button 
              onClick={handleDecline}
              className="text-slate-400 hover:text-slate-600 transition-colors p-1"
              aria-label="Close"
            >
              <FiX className="w-5 h-5" />
            </button>
          </div>

          <p className="text-sm text-slate-600 mb-5 leading-relaxed">
            We use cookies to enhance your browsing experience, display personalized content, and analyze our traffic. By clicking "<span className="font-semibold text-slate-700">Accept All</span>", you consent to our use of cookies according to our{' '}
            <Link to="/cookie-policy" onClick={handleDecline} className="text-blue-600 hover:text-blue-800 font-medium underline-offset-2 hover:underline">
              Cookie Policy
            </Link>.
          </p>

          <div className="flex flex-col sm:flex-row gap-3">
            <button
              onClick={handleDecline}
              className="w-full sm:w-1/2 px-4 py-2.5 rounded-xl border-2 border-slate-100 text-slate-700 font-semibold hover:bg-slate-50 transition-colors text-sm"
            >
              Decline
            </button>
            <button
              onClick={handleAccept}
              className="w-full sm:w-1/2 px-4 py-2.5 rounded-xl bg-blue-600 text-white font-semibold hover:bg-blue-700 shadow-md shadow-blue-600/20 transition-all text-sm"
            >
              Accept All
            </button>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default CookieConsent;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Minus, MessageCircle } from 'lucide-react';
import { faqData } from '../data/content';

const FAQItem = ({ question, answer, isOpen, onClick }) => {
  return (
    <div className={`border-b border-slate-200 last:border-0 transition-colors duration-300 ${isOpen ? 'bg-slate-50' : 'hover:bg-slate-50/50'}`}>
      <button
        className="w-full flex items-center justify-between py-6 px-4 md:px-8 text-left focus:outline-none focus-visible:ring-2 focus-visible:ring-teal-500 rounded-lg"
        onClick={onClick}
      >
        <span className={`text-lg font-bold pr-8 transition-colors ${isOpen ? 'text-teal-600' : 'text-slate-900'}`}>
          {question}
        </span>
        <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 ${isOpen ? 'bg-teal-100 text-teal-600 rotate-180' : 'bg-slate-100 text-slate-500'}`}>
          {isOpen ? <Minus size={18} /> : <Plus size={18} />}
        </div>
      </button>
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.3, ease: 'easeInOut' }}
            className="overflow-hidden"
          >
            <div className="pb-6 px-4 md:px-8 text-slate-600 leading-relaxed text-base">
              {answer}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

const FAQ = () => {
  const [openIndex, setOpenIndex] = useState(0);

  const faqs = faqData;

  return (
    <section id="faq" className="py-24 bg-slate-50 relative overflow-hidden">
      {/* Decorative Blobs */}
      <div className="absolute top-20 -left-20 w-[400px] h-[400px] bg-teal-500/5 rounded-full blur-[80px] pointer-events-none"></div>
      <div className="absolute bottom-20 -right-20 w-[400px] h-[400px] bg-emerald-500/5 rounded-full blur-[80px] pointer-events-none"></div>

      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <div className="text-center mb-16">
          <h2 className="text-teal-600 font-semibold tracking-wide uppercase text-sm mb-3">Questions & Answers</h2>
          <h3 className="text-3xl md:text-5xl font-bold text-slate-900 mb-6 tracking-tight">Frequently Asked Questions</h3>
          <p className="text-lg text-slate-600 max-w-2xl mx-auto">
            Everything you need to know about our services, pricing, and how we build premium digital experiences.
          </p>
        </div>

        <div className="bg-white rounded-3xl border border-slate-200 shadow-xl shadow-slate-200/40 overflow-hidden">
          {faqs.map((faq, index) => (
            <FAQItem
              key={index}
              question={faq.question}
              answer={faq.answer}
              isOpen={openIndex === index}
              onClick={() => setOpenIndex(index === openIndex ? -1 : index)}
            />
          ))}
        </div>

        <div className="mt-12 text-center bg-teal-50 border border-teal-100 rounded-2xl p-8 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="text-left">
            <h4 className="text-xl font-bold text-slate-900 mb-2">Still have questions?</h4>
            <p className="text-slate-600 text-sm">Can't find the answer you're looking for? Please chat to our friendly team.</p>
          </div>
          <a href="/#contact" className="inline-flex items-center gap-2 px-6 py-3 rounded-xl bg-teal-600 text-white font-semibold hover:bg-teal-700 transition-colors shadow-sm whitespace-nowrap">
            <MessageCircle size={18} />
            Get in Touch
          </a>
        </div>
      </div>
    </section>
  );
};

export default FAQ;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageCircle, X, Navigation, Phone } from 'lucide-react';

const FloatingChat = () => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className="bg-white rounded-2xl shadow-2xl border border-slate-100 w-80 mb-4 overflow-hidden origin-bottom-right"
          >
            <div className="bg-gradient-to-r from-teal-600 to-emerald-500 p-5 text-white">
              <h4 className="font-bold text-lg mb-1">Hey there! 👋</h4>
              <p className="text-teal-50 text-sm">We usually reply within a few minutes.</p>
            </div>

            <div className="p-5 bg-slate-50 space-y-4">
              <div className="flex gap-3">
                <div className="w-8 h-8 rounded-full bg-teal-100 text-teal-600 flex items-center justify-center shrink-0 mt-1 font-extrabold text-xs uppercase shadow-sm">
                  TB
                </div>
                <div className="bg-white p-4 rounded-2xl rounded-tl-sm shadow-sm border border-slate-100 text-sm font-medium text-slate-700 leading-relaxed">
                  Welcome to ToolBite! Are you looking for a ready-made template or a completely custom website build?
                </div>
              </div>
            </div>

            <div className="p-4 bg-white border-t border-slate-100 flex flex-col gap-2">
              <a href="https://wa.me/919598037255" target="_blank" rel="noreferrer" className="w-full flex items-center justify-center gap-2 py-3 bg-[#25D366] text-white rounded-xl font-bold text-sm hover:opacity-90 transition-opacity shadow-sm shadow-[#25D366]/20">
                <Phone size={16} fill="currentColor" />
                Chat on WhatsApp
              </a>
              <a href="/#contact" onClick={() => setIsOpen(false)} className="w-full flex items-center justify-center gap-2 py-3 bg-slate-50 text-slate-700 border border-slate-200 rounded-xl font-bold text-sm hover:bg-slate-100 transition-colors">
                <Navigation size={16} />
                Leave a Message
              </a>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-16 h-16 bg-slate-900 text-white rounded-full flex items-center justify-center shadow-2xl hover:bg-teal-600 transition-all duration-300 relative group"
        aria-label="Toggle chat"
      >
        {!isOpen && (
          <div className="absolute inset-0 w-full h-full bg-teal-500 rounded-full animate-ping opacity-20 group-hover:opacity-0 transition-opacity"></div>
        )}
        {isOpen ? <X size={28} className="transform rotate-90 hover:rotate-0 transition-transform duration-300" /> : <MessageCircle size={28} className="group-hover:animate-pulse" />}
      </button>

    </div>
  );
};

export default FloatingChat;

