                  </div>
                </div>

                {/* Card Content */}
                <div className="p-6 flex flex-col flex-1">
                  <div className="mb-3">
                    <h4 className="text-xl font-bold text-slate-900 leading-tight">{tpl.title}</h4>
                  </div>

                  <p className="text-slate-600 text-sm mb-5 h-10 line-clamp-2" title={tpl.shortDescription}>
                    {tpl.shortDescription}
                  </p>

                  <div className="space-y-3 mb-8 flex-1 pt-4 border-t border-slate-50">
                    {/* Map up to 4 features locally */}
                    {tpl.features.slice(0, 4).map((feat, idx) => (
                      <div key={idx} className="flex items-start gap-3 text-sm text-slate-600 font-medium">
                        <Check size={16} className="text-emerald-500 mt-0.5 flex-shrink-0" />
                        <span className="leading-tight">{feat}</span>
                      </div>
                    ))}
                    {tpl.features.length > 4 && (
                      <div className="text-xs font-bold text-teal-600 pl-7">+ {tpl.features.length - 4} more features</div>
                    )}
                  </div>

                  {/* Action Buttons */}
                  <div className="grid grid-cols-2 gap-3 mt-auto pt-4 border-t border-slate-100">
                    <Link 
                      to={`/template/${tpl._id}`} 
                      className="flex items-center justify-center gap-2 py-3 rounded-xl bg-slate-50 text-slate-700 font-semibold text-sm hover:bg-slate-100 transition-colors border border-slate-200 hover:border-slate-300"
                    >
                      <ExternalLink size={16} />
                      Preview
                    </Link>
                    <Link 
                      to={`/template/${tpl._id}`} 
                      className="flex items-center justify-center gap-2 py-3 rounded-xl bg-slate-900 text-white font-semibold text-sm hover:bg-teal-600 transition-all shadow-md hover:shadow-teal-500/25"
                    >
                      <ShoppingCart size={16} />
                      Buy Now
                    </Link>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        )}

      </div>
    </div>
  );
};

export default TemplatesPage;

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import api from '../../services/api';
import toast from 'react-hot-toast';
import { ArrowLeft, Save, UploadCloud, X, Plus } from 'lucide-react';

const TemplateForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEditMode = Boolean(id);

  const [formData, setFormData] = useState({
    title: '',
    category: '',
    price: '',
    shortDescription: '',
    fullDescription: '',
    previewLink: '',
    status: 'active',
  });

  const [features, setFeatures] = useState(['']);
  const [image, setImage] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [loading, setLoading] = useState(isEditMode);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (isEditMode) {
      fetchTemplate();
    }
  }, [id]);

  const fetchTemplate = async () => {
    try {
      const { data } = await api.get(`/templates/${id}`);
      setFormData({
        title: data.title,
        category: data.category,
        price: data.price,
        shortDescription: data.shortDescription,
        fullDescription: data.fullDescription || '',
        previewLink: data.previewLink || '',
        status: data.status,
      });
      setFeatures(data.features.length > 0 ? data.features : ['']);
      setImagePreview(data.imageUrl);
    } catch (error) {
      toast.error('Failed to load template');
      navigate('/admin/dashboard');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleFeatureChange = (index, value) => {
    const newFeatures = [...features];
    newFeatures[index] = value;
    setFeatures(newFeatures);
  };

  const addFeature = () => setFeatures([...features, '']);

  const removeFeature = (index) => {
    const newFeatures = features.filter((_, i) => i !== index);
    setFeatures(newFeatures.length ? newFeatures : ['']);
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        toast.error('File exceeds 5MB limit');
        return;
      }
      setImage(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);

    // Clean features array
    const cleanFeatures = features.filter(f => f.trim() !== '');

    const data = new FormData();
    data.append('title', formData.title);
    data.append('category', formData.category);
    data.append('price', formData.price);
    data.append('shortDescription', formData.shortDescription);
    data.append('fullDescription', formData.fullDescription);
    data.append('previewLink', formData.previewLink);
    data.append('status', formData.status);

    // For our node backend parsing logic:
    data.append('features', JSON.stringify(cleanFeatures));

    if (image) {
      data.append('image', image);
    } else if (!isEditMode) {
      toast.error('Please upload an image');
      setSubmitting(false);
      return;
    }

    try {
      if (isEditMode) {
        await api.put(`/templates/${id}`, data, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Template updated successfully');
      } else {
        await api.post('/templates', data, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Template created successfully');
      }
      navigate('/admin/dashboard');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save template');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <div className="text-center py-20 animate-pulse text-slate-500 font-medium">Loading template data...</div>;

  return (
    <div className="max-w-4xl mx-auto pb-12">
      <div className="flex items-center mb-8">
        <Link to="/admin/dashboard" className="mr-4 p-2 text-slate-500 hover:bg-white hover:shadow-sm rounded-full transition">
          <ArrowLeft className="w-5 h-5" />
        </Link>
        <h1 className="text-3xl font-extrabold text-slate-900">
          {isEditMode ? 'Edit Template' : 'Add New Template'}
        </h1>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-10">
        <form onSubmit={handleSubmit} className="space-y-8">

          {/* Image Upload Area */}
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Template Image</label>
            <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-slate-300 border-dashed rounded-xl hover:border-blue-400 hover:bg-blue-50/50 transition cursor-pointer relative group">
              <div className="space-y-2 text-center">
                {imagePreview ? (
                  <div className="relative inline-block">
                    <img src={imagePreview} alt="Preview" className="h-48 rounded-lg object-cover shadow-sm border border-slate-200" />
                    <button 
                      type="button" 
                      onClick={(e) => { e.preventDefault(); setImage(null); setImagePreview(''); }}
                      className="absolute -top-3 -right-3 z-10 bg-red-100 text-red-600 rounded-full p-1.5 hover:bg-red-200 hover:scale-110 transition shadow-sm"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  </div>
                ) : (
                  <>
                    <UploadCloud className="mx-auto h-12 w-12 text-slate-300 group-hover:text-blue-500 transition" />
                    <div className="flex text-sm text-slate-600 justify-center">
                      <label htmlFor="file-upload" className="relative cursor-pointer bg-white rounded-md font-medium text-blue-600 hover:text-blue-500 py-1 transition">
                        <span>Upload a file</span>
                        <input id="file-upload" name="image" type="file" className="sr-only" onChange={handleImageChange} accept="image/*" />
                      </label>
                      <p className="pl-1 py-1">or click here</p>
                    </div>
                    <p className="text-xs text-slate-400 font-medium tracking-wide border border-slate-100 bg-slate-50 rounded-md py-1 px-3 inline-block">PNG, JPG, WEBP up to 5MB</p>
                  </>
                )}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Title</label>
              <input type="text" name="title" required value={formData.title} onChange={handleChange} className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition" placeholder="SaaS Landing Page" />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Category</label>
              <select name="category" required value={formData.category} onChange={handleChange} className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition cursor-pointer appearance-none">
                <option value="" disabled>Select a category</option>
                <option value="E-Commerce">E-Commerce</option>
                <option value="Portfolio">Portfolio</option>
                <option value="Landing Page">Landing Page</option>
                <option value="Blog">Blog</option>
                <option value="SaaS">SaaS</option>
                <option value="Corporate">Corporate</option>
                <option value="Admin Dashboard">Admin Dashboard</option>
                <option value="Other">Other</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Price ($)</label>
              <input type="number" name="price" required value={formData.price} onChange={handleChange} min="0" step="0.01" className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition" placeholder="49.99" />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Status</label>
              <select name="status" value={formData.status} onChange={handleChange} className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition cursor-pointer appearance-none">
                <option value="active">Active (Visible formatting)</option>
                <option value="inactive">Inactive (Hidden formatting)</option>
              </select>
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Preview Demo Link</label>
              <input type="url" name="previewLink" value={formData.previewLink} onChange={handleChange} className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition" placeholder="https://demo.toolbite.com/..." />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Short Description</label>
              <input type="text" name="shortDescription" required value={formData.shortDescription} onChange={handleChange} className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition" placeholder="A brief one-liner summarizing the template" />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Full Description</label>
              <textarea name="fullDescription" rows="5" value={formData.fullDescription} onChange={handleChange} className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition resize-none" placeholder="Detailed insights about what the template features..."></textarea>
            </div>
          </div>

          <div className="space-y-4 pt-2">
            <label className="block text-sm font-semibold text-slate-700">Template Details & Features</label>
            {features.map((feature, index) => (
              <div key={index} className="flex gap-3">
                <input 
                  type="text" 
                  value={feature} 
                  onChange={(e) => handleFeatureChange(index, e.target.value)} 
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 outline-none transition" 
                  placeholder="e.g., Responsive Design, React Integration..." 
                />
                <button type="button" onClick={() => removeFeature(index)} className="px-4 text-red-500 bg-red-50 hover:bg-red-100 hover:text-red-600 rounded-xl transition shadow-sm border border-red-100">
                  <X className="w-5 h-5 mx-auto" />
                </button>
              </div>
            ))}
            <button type="button" onClick={addFeature} className="text-blue-600 text-sm font-bold hover:text-blue-800 transition flex items-center mt-3 px-2 py-1 rounded-lg hover:bg-blue-50">
              <Plus className="w-4 h-4 mr-1 stroke-[3px]" /> Add Another Feature
            </button>
          </div>

          <div className="pt-8 border-t border-slate-100">
            <button 
              type="submit" 
              disabled={submitting} 
              className="w-full flex justify-center items-center py-4 px-4 border border-transparent rounded-xl shadow-md shadow-blue-500/30 text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition duration-200 font-bold disabled:opacity-70 disabled:cursor-not-allowed"
            >
              {submitting ? (
                 <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
              ) : (
                <>
                  <Save className="w-5 h-5 mr-2" />
                  {isEditMode ? 'Update Template' : 'Publish Template'}
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default TemplateForm;

import React, { useState, useEffect, useMemo } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { Plus, Edit, Trash2, CheckCircle, XCircle, Search, Filter } from 'lucide-react';
import toast from 'react-hot-toast';

const TemplateList = () => {
  const [templates, setTemplates] = useState([]);
  const [loading, setLoading] = useState(true);

  // Filters and Search
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState('');
  const [filterStatus, setFilterStatus] = useState('');

  useEffect(() => {
    fetchTemplates();
  }, []);

  const fetchTemplates = async () => {
    try {
      const { data } = await api.get('/templates');
      setTemplates(data);
    } catch (error) {
      toast.error('Failed to load templates');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this template?')) {
      try {
        await api.delete(`/templates/${id}`);
        toast.success('Template deleted successfully');
        fetchTemplates();
      } catch (error) {
        toast.error('Failed to delete template');
      }
    }
  };

  const toggleStatus = async (id) => {
    try {
      await api.patch(`/templates/${id}/status`);
      toast.success('Status updated');
      fetchTemplates();
    } catch (error) {
      toast.error('Failed to update status');
    }
  };

  // Derive unique categories for the filter dropdown
  const categories = useMemo(() => {
    const cats = templates.map(t => t.category);
    return [...new Set(cats)];
  }, [templates]);

  // Apply filters and search
  const filteredTemplates = useMemo(() => {
    return templates.filter((template) => {
      const matchesSearch = template.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            template.shortDescription.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filterCategory ? template.category === filterCategory : true;
      const matchesStatus = filterStatus ? template.status === filterStatus : true;
      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [templates, searchTerm, filterCategory, filterStatus]);

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto pb-12">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center mb-8 gap-4">
        <h1 className="text-3xl font-extrabold text-slate-800">Templates</h1>
        <Link
          to="/admin/templates/new"
          className="bg-blue-600 text-white px-5 py-2.5 rounded-xl text-sm font-semibold hover:bg-blue-700 transition flex items-center shadow-md shadow-blue-500/30"
        >
          <Plus className="w-5 h-5 mr-2" />
          Add Template
        </Link>
      </div>

      {/* Filters & Search Bar */}
      <div className="bg-white p-4 rounded-t-2xl border-x border-t border-slate-200 flex flex-col md:flex-row gap-4 justify-between items-center shadow-sm">
        <div className="relative w-full md:w-96">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
          </div>
          <input
            type="text"
            placeholder="Search templates..."
            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition text-sm text-slate-700"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-col sm:flex-row w-full md:w-auto gap-4">
          <div className="relative w-full sm:w-48">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Filter className="h-4 w-4 text-slate-400" />
            </div>
            <select
              className="w-full pl-9 pr-8 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition text-sm text-slate-700 appearance-none cursor-pointer"
              value={filterCategory}
              onChange={(e) => setFilterCategory(e.target.value)}
            >
              <option value="">All Categories</option>
              {categories.map((cat, i) => (
                <option key={i} value={cat}>{cat}</option>
              ))}
            </select>
          </div>

          <select
            className="w-full sm:w-40 px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition text-sm text-slate-700 cursor-pointer appearance-none"
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
          >
            <option value="">All Statuses</option>
            <option value="active">Active</option>
            <option value="inactive">Inactive</option>
          </select>
        </div>
      </div>

      <div className="bg-white rounded-b-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-y border-slate-200">
              <tr>
                <th className="px-6 py-4">Template</th>
                <th className="px-6 py-4">Category & Price</th>
                <th className="px-6 py-4 hidden md:table-cell">Created Date</th>
                <th className="px-6 py-4 text-center">Status</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTemplates.length === 0 ? (
                <tr>
                  <td colSpan="5" className="px-6 py-16 text-center text-slate-500">
                    <div className="flex flex-col items-center">
                      <Search className="h-10 w-10 text-slate-300 mb-3" />
                      <p className="text-base font-medium text-slate-600">No templates found</p>
                      <p className="text-sm mt-1">Try adjusting your filters or search term.</p>
                    </div>
                  </td>
                </tr>
              ) : (
                filteredTemplates.map((template) => (
                  <tr key={template._id} className="hover:bg-slate-50/70 transition-colors group">
                    <td className="px-6 py-4">
                      <div className="flex items-center">
                        <img 
                          src={template.imageUrl} 
                          alt={template.title} 
                          className="w-14 h-14 rounded-lg object-cover mr-4 shadow-sm border border-slate-200"
                        />
                        <div>
                          <p className="font-bold text-slate-900 text-base">{template.title}</p>
                          <p className="text-xs text-slate-500 mt-0.5 max-w-[200px] md:max-w-xs truncate" title={template.shortDescription}>
                            {template.shortDescription}
                          </p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="inline-block px-2.5 py-1 rounded-md bg-blue-50 text-blue-700 text-xs font-semibold tracking-wide mb-1">
                        {template.category}
                      </span>
                      <p className="font-bold text-slate-800">${template.price}</p>
                    </td>
                    <td className="px-6 py-4 hidden md:table-cell whitespace-nowrap text-slate-500">
                      {new Date(template.createdAt).toLocaleDateString('en-US', {
                        year: 'numeric', month: 'short', day: 'numeric'
                      })}
                    </td>
                    <td className="px-6 py-4 text-center whitespace-nowrap">
                      <button 
                        onClick={() => toggleStatus(template._id)}
                        className={`inline-flex items-center px-3 py-1.5 rounded-full text-xs font-bold transition-all shadow-sm ${
                          template.status === 'active' 
                            ? 'bg-green-100 text-green-700 hover:bg-green-200 hover:shadow-green-500/20' 
                            : 'bg-slate-100 text-slate-600 hover:bg-slate-200 hover:shadow-slate-500/20'
                        }`}
                      >
                        {template.status === 'active' ? <CheckCircle className="w-3.5 h-3.5 mr-1.5" /> : <XCircle className="w-3.5 h-3.5 mr-1.5" />}
                        <span className="capitalize">{template.status}</span>
                      </button>
                    </td>
                    <td className="px-6 py-4 text-right whitespace-nowrap">
                      <div className="flex items-center justify-end opacity-100 md:opacity-0 group-hover:opacity-100 transition-opacity">
                        <Link 
                          to={`/admin/templates/edit/${template._id}`}
                          className="p-2 bg-white border border-slate-200 text-blue-600 hover:bg-blue-50 hover:border-blue-200 rounded-lg transition-colors mr-2 shadow-sm"
                          title="Edit"
                        >
                          <Edit className="w-4 h-4" />
                        </Link>
                        <button 
                          onClick={() => handleDelete(template._id)}
                          className="p-2 bg-white border border-slate-200 text-red-600 hover:bg-red-50 hover:border-red-200 rounded-lg transition-colors shadow-sm"
                          title="Delete"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default TemplateList;
